mapper.select:
SELECT m.id, m.tomb_id, t.name AS tomb_name, m.visitor_name, m.avatar, m.content, m.status, m.reject_reason, m.create_time FROM tomb_message m LEFT JOIN tomb t ON m.tomb_id = t.id AND t.del_flag = 0
AND (m.content LIKE CONCAT('%', #{param.keyword, jdbcType=VARCHAR}, '%') OR t.name LIKE CONCAT('%', #{param.keyword, jdbcType=VARCHAR}, '%'))
AND ( m.status = #{param.status}
OR m.user_id = #{param.currentUserId}
)
AND m.tomb_id = #{param.tombId}
AND (t.family_id IN (SELECT id FROM family WHERE (founder_id = #{param.currentUserId} OR id IN (SELECT family_id FROM family_member WHERE user_id = #{param.currentUserId} AND del_flag = 0)) AND del_flag = 0) OR (t.family_id IS NULL AND (t.user_id = #{param.currentUserId} OR t.create_by = #{param.currentUserId})))
AND m.del_flag = 0
ORDER BY m.id DESC
